+				defer store.Close()
+			}
+			if linkProject != "" {
+				project = linkProject
+			}
+			if project == "" {
+				plansDir, err := resolvePlansDir()
+				if err != nil {
+					return err
+				}
+				project = projectFromPlansDir(plansDir)
+			}
+			n, err := executeTaskLinkClickUp(project, store)
+			if err != nil {
+				return err
+			}
+			fmt.Printf("linked %d plan(s) to ClickUp tasks\n", n)
